-- Script completo de migração de bancas do schema antigo MySQL para o novo PostgreSQL
-- 
-- PASSO 1: Execute este script para criar as tabelas raw
-- PASSO 2: Importe os dados do MySQL dump nas tabelas raw_*
-- PASSO 3: Execute a parte de migração para transferir para o schema novo

-- =====================================================
-- PARTE 1: CRIAR TABELAS RAW TEMPORÁRIAS
-- =====================================================


-- Raw table for old banca data
CREATE TEMP TABLE IF NOT EXISTS raw_banca (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    curso INTEGER NOT NULL,
    autor VARCHAR(255) NOT NULL,
    turma VARCHAR(45) NOT NULL,
    ano INTEGER NOT NULL,
    semestre_letivo CHAR(1),
    matricula VARCHAR(10),
    tipo_banca VARCHAR(10) NOT NULL,
    titulo_trabalho VARCHAR(255) NOT NULL,
    resumo TEXT NOT NULL,
    abstract TEXT NOT NULL,
    palavras_chave VARCHAR(512) NOT NULL,
    data_realizacao TIMESTAMP NOT NULL,
    nota_final DOUBLE PRECISION,
    local VARCHAR(255),
    pronome_autor INTEGER NOT NULL,
    visible BOOLEAN NOT NULL
);

-- Raw table for old usuario_banca data
-- =====================================================
-- AQUI VOCÊ DEVE INSERIR OS DADOS DO DUMP ANTIGO NAS TABELAS raw_*
-- Exemplo:
-- INSERT INTO raw_curso VALUES (1,'Ciência da Computação','BCC','MATA67','Rita Suzana Pitangueira Maciel','Coordenador do Curso de Bacharelado em Ciência da Computação');
-- INSERT INTO raw_curso VALUES (2,'Sistemas de Informação','BSI','MATC98','Tatiane Nogueira Rios','Coordenador do Curso de Bacharelado em Sistemas de Informação');
-- ... (todos os outros INSERTs do dump antigo)
-- =====================================================

CREATE TEMP TABLE IF NOT EXISTS raw_usuario_banca (
    id INTEGER PRIMARY KEY,
    id_usuario INTEGER NOT NULL,
    id_banca INTEGER NOT NULL,
    role VARCHAR(64) NOT NULL,
    nota DOUBLE PRECISION
);

-- =====================================================
-- PARTE 2: MIGRAÇÃO DAS TABELAS RAW PARA O SCHEMA NOVO
-- =====================================================

-- 2. Migrar as bancas com os mapeamentos necessários
    id,
    orientador_id,
    curso_id, 
    autor,
    matricula,
    turma,
    periodo_academico,
    titulo_trabalho,
    resumo,
    abstract,
    palavras_chave,
    data_realizacao,
    nota_final,
    local,
    modalidade,
    visible,
    aluno_id
)
SELECT 
    b.id,
    -- Para orientador_id, pegar o usuário com role 'orientador' da usuario_banca
    (SELECT ub.id_usuario 
     FROM raw_usuario_banca ub 
     WHERE ub.id_banca = b.id AND ub.role = 'orientador' 
     LIMIT 1) as orientador_id,
    b.curso as curso_id,
    b.autor,
    b.matricula,
    b.turma,
    -- Concatenar ano e semestre para formar período acadêmico
    CONCAT(b.ano, '.', b.semestre_letivo) as periodo_academico,
    b.titulo_trabalho,
    b.resumo,
    b.abstract,
    b.palavras_chave,
    b.data_realizacao,
    CAST(b.nota_final as TEXT) as nota_final,
    b.local,
    -- Mapear tipo_banca para modalidade (assumindo 'local' se não especificado)
    CASE 
        WHEN b.tipo_banca = 'remoto' THEN 'remoto'::modalidade
        ELSE 'local'::modalidade
    END as modalidade,
    b.visible,
    b.user_id as aluno_id
FROM raw_banca b
ON CONFLICT ON CONSTRAINT aluno_curso_unique DO UPDATE SET
    orientador_id = EXCLUDED.orientador_id,
    curso_id = EXCLUDED.curso_id,
    autor = EXCLUDED.autor,
    matricula = EXCLUDED.matricula,
    turma = EXCLUDED.turma,
    periodo_academico = EXCLUDED.periodo_academico,
    titulo_trabalho = EXCLUDED.titulo_trabalho,
    resumo = EXCLUDED.resumo,
    abstract = EXCLUDED.abstract,
    palavras_chave = EXCLUDED.palavras_chave,
    data_realizacao = EXCLUDED.data_realizacao,
    nota_final = EXCLUDED.nota_final,
    local = EXCLUDED.local,
    modalidade = EXCLUDED.modalidade,
    visible = EXCLUDED.visible,
    aluno_id = EXCLUDED.aluno_id;

-- 3. Migrar as relações usuario_banca (esta tabela já tem estrutura similar)
SELECT 
    id,
    id_usuario,
    id_banca,
    role,
    CAST(nota as TEXT) as nota
FROM usuario_banca
ON CONFLICT (id) DO NOTHING;
